import math as _math

def _d2(x, y, c1, c2):
    return c1 if (x + y) % 2 == 0 else c2


def _gen_comet():
    W, H, FRAMES = 32, 32, 10
    arr = []
    for f in range(FRAMES):
        for y in range(H):
            for x in range(W):
                if f == 9:
                    d = _math.sqrt((x-16)**2 + (y-16)**2)
                    c = 67 if d < 12 else _d2(x,y,67,0) if d < 15 else 0
                else:
                    hx, hy = 10+f, 20-f
                    dh = _math.sqrt((x-hx)**2+(y-hy)**2)
                    if dh < 3.0:   c = 65
                    elif dh < 4.5: c = _d2(x,y,65,70)
                    else:
                        c = 0
                        tl = min(f*2+4, 18)
                        for t in range(1, tl):
                            tx, ty = hx-t, hy+t
                            if abs(x-tx) <= 1 and abs(y-ty) <= 1:
                                c = 67 if t/tl < 0.4 else _d2(x,y,67,66) if t/tl < 0.7 else _d2(x,y,66,0)
                                break
                arr.append(c)
    return arr


def _gen_impact():
    W, H, FRAMES = 48, 32, 8
    arr = []
    for f in range(FRAMES):
        for y in range(H):
            for x in range(W):
                cx, cy = 24, 20
                d = _math.sqrt((x-cx)**2+(y-cy)**2)
                if f < 3:
                    r = 4+f*5
                    if d < r*0.4:   c = 65
                    elif d < r*0.7: c = _d2(x,y,65,70)
                    elif d < r:     c = _d2(x,y,67,70)
                    elif d < r+2:   c = _d2(x,y,67,0)
                    else:           c = 0
                elif f < 6:
                    r = 18-(f-3)*2
                    ang = _math.atan2(y-cy, x-cx)
                    seg = int((ang+_math.pi)/(_math.pi/6))%12
                    c = 33 if (d < r and seg%2==f%2 and d < r*0.5) else 18 if (d < r and seg%2==f%2) else 9 if d < r else 0
                else:
                    r = 10-(f-6)*3
                    c = _d2(x,y,19,0) if r > 0 and d < r else 0
                arr.append(c)
    return arr


def _gen_chest():
    W, H, FRAMES = 16, 16, 6
    arr = []
    for f in range(FRAMES):
        for y in range(H):
            for x in range(W):
                bx = 2 <= x <= 13
                by = 7 <= y <= 14
                lt = 2-min(f,4)
                lidy = lt <= y <= 6
                c = 0
                if bx and by:
                    if x in (2,13) or y == 14: c = 72
                    elif y == 7: c = 72
                    elif f >= 2 and y >= 9 and 4 <= x <= 11:
                        dist = abs(x-7.5)+abs(y-10)
                        c = 66 if dist < 3 else 70 if dist < 5 else 33
                    else: c = 33 if x < 8 else 18
                elif bx and lidy:
                    c = 72 if y == lt or x in (2,13) else 18 if x < 8 else 33
                    if y == 6 and bx: c = 19
                arr.append(c)
    return arr


def _gen_coins():
    W, H, FRAMES = 24, 20, 6
    paths = [(8,18,4,4),(12,18,12,2),(16,18,20,6)]
    arr = []
    for f in range(FRAMES):
        grid = [0]*(W*H)
        for sx,sy,ex,ey in paths:
            if f < 3:
                t=f/2.0; cx=sx+(ex-sx)*t*0.5; cy=sy-(sy-ey)*t*0.5
            else:
                t=(f-3)/2.0; cx=sx+(ex-sx)*(0.5+t*0.5); cy=ey+(sy-ey)*(1.0-t)
            for dy in range(-1,2):
                for dx in range(-1,2):
                    bx,by=int(cx)+dx,int(cy)+dy
                    if 0<=bx<W and 0<=by<H:
                        grid[by*W+bx]=70 if dx==0 and dy==0 else 66
        arr.extend(grid)
    return arr


def _gen_traveler(facing_right=False):
    W, H, FRAMES = 16, 24, 6
    result = []
    for f in range(FRAMES):
        frame = [0]*(W*H)
        def sp(x,y,c):
            if 0<=x<W and 0<=y<H: frame[y*W+x]=c
        cx=8
        for dy in range(-2,3):
            for dx in range(-2,3):
                if abs(dx)+abs(dy) < 4:
                    sp(cx+dx,3+dy, 72 if abs(dx)==2 or abs(dy)==2 else 18)
        for ry in range(6,18):
            hw=min(2+int((ry-6)*0.35),5)
            for rx in range(cx-hw,cx+hw+1):
                sp(rx,ry, 72 if abs(rx-cx)==hw else 19 if (rx+ry)%3!=0 else 20)
        leg=f%2
        for ry in range(18,24):
            lo=1 if (leg==0 and ry>20) else (-1 if (leg==1 and ry>20) else 0)
            ro=-lo
            for xp in (cx-2+lo, cx-1+lo, cx+1+ro, cx+2+ro):
                sp(xp,ry,72)
        if facing_right:
            m=[0]*(W*H)
            for ry in range(H):
                for rx in range(W): m[ry*W+(W-1-rx)]=frame[ry*W+rx]
            result.extend(m)
        else:
            result.extend(frame)
    return result


def _gen_portal():
    W, H, FRAMES = 24, 32, 8
    arr = []
    for f in range(FRAMES):
        for y in range(H):
            for x in range(W):
                cx,cy=12,18
                dxe=(x-cx)/10.0; dye=(y-cy)/14.0
                d=_math.sqrt(dxe*dxe+dye*dye)
                if f==0: c=69 if d < 0.15 else 0
                elif f<=4:
                    r=f*0.22
                    if abs(d-r) < 0.12: c=69
                    elif abs(d-r) < 0.22: c=_d2(x,y,71,69)
                    elif d < r-0.12: c=13 if (x+y*3)%5==0 else 0
                    else: c=0
                else:
                    if d > 1.0: c=0
                    elif d > 0.85: c=69 if (x+y+f)%3==0 else 71
                    elif d > 0.70: c=71 if (x*y+f)%4==0 else 69
                    else:
                        angle=_math.atan2(y-cy,x-cx)
                        swirl=(angle+f*0.8)%(_math.pi*2)
                        c=69 if swirl < _math.pi else 13
                arr.append(c)
    return arr


def _gen_fireworks():
    W, H, FRAMES = 48, 48, 14
    bx0,by0=24,24
    spoke_colors=[68,69,66]
    arr=[]
    for f in range(FRAMES):
        grid=[0]*(W*H)
        def sp2(x,y,c):
            if 0<=x<W and 0<=y<H: grid[y*W+x]=c
        if f < 4:
            ry=40-f*5
            for dy in range(5): sp2(bx0,ry+dy,66); sp2(bx0+1,ry+dy,70)
        elif f < 11:
            t=f-4; radius=t*3+2
            for s in range(12):
                angle=s*(2*_math.pi/12); sc=spoke_colors[s%3]
                for r in range(1,radius+1):
                    px=int(bx0+r*_math.cos(angle)); py=int(by0+r*_math.sin(angle))
                    sp2(px,py, sc if r < radius-2 else _d2(px,py,sc,0))
            if t < 3:
                for dy in range(-2,3):
                    for dx in range(-2,3):
                        dist=abs(dx)+abs(dy)
                        if dist < 3: sp2(bx0+dx,by0+dy, 65 if dist==0 else 70)
        else:
            ft=f-11; radius=20-ft*5
            if radius > 0:
                for s in range(12):
                    angle=s*(2*_math.pi/12); sc=spoke_colors[s%3]
                    for r in range(max(0,radius-2),radius+1):
                        px=int(bx0+r*_math.cos(angle)); py=int(by0+r*_math.sin(angle))
                        sp2(px,py,_d2(px,py,sc,0))
        arr.extend(grid)
    return arr


def _gen_diamond():
    W, H, FRAMES = 10, 12, 6
    glints=[(2,2),(7,3),(5,7),(3,9),(8,5)]
    arr=[]
    for f in range(FRAMES):
        for y in range(H):
            for x in range(W):
                cx,cy=5.0,6.0
                norm=abs(x-cx)/4.5+abs(y-cy)/5.5
                if norm > 1.0: c=0
                elif f < 2:
                    s=0.6+f*0.2; sm=abs(x-cx)/(4.5*s)+abs(y-cy)/(5.5*s)
                    c=71 if sm <= 1.0 else 0
                else:
                    if norm < 0.2: c=71
                    elif norm < 0.4: c=71 if (x < cx and y < cy) else 69
                    elif norm < 0.65: c=69 if x < cx else 13
                    elif norm < 0.85: c=13
                    else: c=_d2(x,y,13,0)
                    gx,gy=glints[f%len(glints)]
                    if x==gx and y==gy and norm <= 0.8: c=65
                arr.append(c)
    return arr


