IMPACT_W, IMPACT_H, IMPACT_FRAMES = 48, 32, 8
IMPACT = _gen_impact()

CHEST_W, CHEST_H, CHEST_FRAMES = 16, 16, 6
CHEST = _gen_chest()

COINS_W, COINS_H, COINS_FRAMES = 24, 20, 6
COINS = _gen_coins()

TRAVELER_W, TRAVELER_H, TRAVELER_FRAMES = 16, 24, 6
TRAVELER = _gen_traveler(facing_right=False)

TRAVELER_LEAVE_W, TRAVELER_LEAVE_H, TRAVELER_LEAVE_FRAMES = 16, 24, 6
TRAVELER_LEAVE = _gen_traveler(facing_right=True)

PORTAL_W, PORTAL_H, PORTAL_FRAMES = 24, 32, 8
PORTAL = _gen_portal()

FIREWORKS_W, FIREWORKS_H, FIREWORKS_FRAMES = 48, 48, 14
FIREWORKS = _gen_fireworks()

DIAMOND_W, DIAMOND_H, DIAMOND_FRAMES = 10, 12, 6
DIAMOND = _gen_diamond()


