def _gen_font():
    arr = []
    for code in range(32, 128):
        glyph = _GLYPHS.get(chr(code), _GLYPHS[' '])
        for row in range(8):
            if row < 7:
                bits = glyph[row]
                for bit in range(4, -1, -1):
                    arr.append(1 if (bits >> bit) & 1 else 0)
                arr.append(0)
            else:
                arr.extend([0]*6)
    return arr

FONT = _gen_font()


# ── Restore clean reference pixels over the former watermark area ─
def _patch_rows(arr, sprite_w, y0, x0, rows):
    for dy, row in enumerate(rows):
        base = (y0 + dy) * sprite_w + x0
        arr[base:base + len(row)] = row

